changeSet.sql:
ALTER TABLE clinlims.inventory_item
DROP CONSTRAINT IF EXISTS chk_item_type;

ALTER TABLE clinlims.inventory_item
ADD CONSTRAINT chk_item_type
CHECK (item_type IN (
    'REAGENT', 'RDT', 'CARTRIDGE', 'EQUIPMENT', 'CONSUMABLE',
    'HIV_KIT', 'SYPHILIS_KIT', 'ENZYME', 'ANTIBIOTICS'
));
